import{_ as n,b0 as t,aC as l,aF as i,az as s,aG as e,P as p,aa as r,al as h,aq as o}from"./chunks/framework.DMsx7SBw.js";const E=JSON.parse('{"title":"内存管理","description":"","frontmatter":{"title":"内存管理","order":30},"headers":[],"relativePath":"kernel/linux/mm/index.md","filePath":"kernel/linux/mm/index.md"}'),d={name:"kernel/linux/mm/index.md"},k={class:"MathJax",jax:"SVG",style:{direction:"ltr",position:"relative"}},m={style:{overflow:"visible","min-height":"1px","min-width":"1px","vertical-align":"0"},xmlns:"http://www.w3.org/2000/svg",width:"2.919ex",height:"1.904ex",role:"img",focusable:"false",viewBox:"0 -841.7 1290.1 841.7","aria-hidden":"true"};function c(g,a,T,u,_,x){return t(),l("div",null,[a[4]||(a[4]=i('<h1 id="内存管理" tabindex="-1">内存管理 <a class="header-anchor" href="#内存管理" aria-label="Permalink to “内存管理”">​</a></h1><p>操作系统为进程提供虚拟内存，每个应用程序进程都认为自己独占全部、连续的内存。在 64 位系统上，虚拟地址范围为 0x0000_00000000 到 0x7fff_ffffffff（128TB）。</p><p>虚拟内存机制使得用户程序编写时无须关注底层物理内存，同时提供了进程之间的内存隔离能力和访问权限控制。但虚拟内存的引入也带来了内存申请延迟和访问延迟的问题。</p><p><img src="'+p+'" alt=""></p><p>虚拟内存的管理依附于进程管理。 <img src="'+r+'" alt=""></p><p>Linux 内存管理子系统按照职责可以分为以下几个模块：</p><ul><li><strong>内存地址翻译</strong>：CPU 通过 MMU 将虚拟地址翻译为物理地址，依赖页表和 TLB 硬件缓存。操作系统负责维护页表映射规则。</li><li><strong><a href="./pmm">物理内存管理</a></strong>：内核如何探测物理内存布局（E820 表）、如何分配和管理物理页框（伙伴系统、SLUB 分配器）。</li><li><strong><a href="./mmap">虚拟内存映射</a></strong>：内核虚拟地址的线性映射、缺页异常处理、mmap 系统调用、共享内存。</li><li><strong><a href="./swap">内存交换</a></strong>：物理内存不足时，将匿名页换出到磁盘的 swap 分区，以及页替换策略（FIFO、LRU）。</li><li><strong><a href="./reclaim">内存回收</a></strong>：页面回收、内存压缩（zswap/zram）、内存碎片（外部碎片与内部碎片）、内存紧缩、OOM Killer。</li></ul><h2 id="内存地址翻译" tabindex="-1">内存地址翻译 <a class="header-anchor" href="#内存地址翻译" aria-label="Permalink to “内存地址翻译”">​</a></h2><p>根据冯诺依曼模型，CPU 需要从硬盘加载数据，填入到内存中，然后再通过读写内存中的数据进行临时存储，最后将内存中的数据持久化到硬盘上。CPU 在访问内存的时候需要使用特定的内存操作相关指令，并需要指定操作的内存虚拟地址。</p><p>内存地址翻译是将进程的虚拟地址转换为物理地址的过程，依赖于硬件和操作系统的协作。主要涉及以下几个核心组件：</p><ul><li><p>内存基地址寄存器 内存基地址寄存器（如 x86 架构的 CR3，ARM 架构的 TTBR）存放当前进程页表的物理基地址。每次进程切换时，操作系统会更新该寄存器，MMU 通过它定位页表，实现不同进程的虚拟内存空间隔离。</p></li><li><p>MMU MMU（Memory Management Unit）内存管理单元是 CPU 内部负责虚拟地址到物理地址转换的硬件模块。它根据当前进程的内存基地址寄存器中的值去获取页表信息，从而根据页表信息将虚拟地址分级映射到物理地址，实现内存隔离和保护。</p><p>CPU 在执行任何需要读写内存的指令时，均需要通过其中的 MMU 来进行内存访问。而内存地址翻译是 MMU 的固定流程。意味着 CPU 只能使用虚拟地址、指令传参的时候是虚拟地址、CPU 内存相关的指令逻辑对物理地址不感知，负责从物理内存上取数据的是 MMU。<strong>应用层的程序员只需要关注虚拟内存即可，而无须关注物理内存的管理</strong>，并且操作系统其实也不需要具体地实现页表查询的算法，操作系统主要需要管理好 MMU 的映射规则和行为即可。</p></li><li><p>TLB 多级页表虽然节省了内存空间，但会增加地址转换的访问延迟。为提升效率，CPU 内部集成了 TLB（Translation Lookaside Buffer，转址旁路缓存），用于缓存最近访问过的虚拟页到物理页的映射。TLB 是有限大小的高速缓存，命中时可直接获得物理地址，未命中时需重新查页表并更新 TLB。</p></li></ul><h2 id="内存分配" tabindex="-1">内存分配 <a class="header-anchor" href="#内存分配" aria-label="Permalink to “内存分配”">​</a></h2><p>常见的虚拟内存管理算法有分段和分页。Linux 采用分页方式，不使用分段方式的原因是分段容易产生<strong>外部内存碎片</strong>。</p><h3 id="分页" tabindex="-1">分页 <a class="header-anchor" href="#分页" aria-label="Permalink to “分页”">​</a></h3><p>分页机制将内存地址空间按页（默认 4KB）为单位管理。</p><p>对于一个进程来说，进程的内存需要进行动态分配使用，按需申请，每次申请一个或者多个页表，每个虚拟页表都可以对应一个真实的物理地址中的页表。操作系统以进程为单位，为程序创建一个<strong>内存地址映射表</strong>，也叫<strong>页表</strong>，页表记录着从虚拟地址空间中的一个页的首地址，到对应的真实物理页的内存条上的首地址，的映射关系。</p><h3 id="多级页表" tabindex="-1">多级页表 <a class="header-anchor" href="#多级页表" aria-label="Permalink to “多级页表”">​</a></h3>',17)),s("p",null,[a[2]||(a[2]=e("64 位系统的虚拟地址空间极大（",-1)),s("mjx-container",k,[(t(),l("svg",m,[...a[0]||(a[0]=[i('<g stroke="currentColor" fill="currentColor" stroke-width="0" transform="scale(1,-1)"><g data-mml-node="math"><g data-mml-node="msup"><g data-mml-node="mn"><path data-c="32" d="M109 429Q82 429 66 447T50 491Q50 562 103 614T235 666Q326 666 387 610T449 465Q449 422 429 383T381 315T301 241Q265 210 201 149L142 93L218 92Q375 92 385 97Q392 99 409 186V189H449V186Q448 183 436 95T421 3V0H50V19V31Q50 38 56 46T86 81Q115 113 136 137Q145 147 170 174T204 211T233 244T261 278T284 308T305 340T320 369T333 401T340 431T343 464Q343 527 309 573T212 619Q179 619 154 602T119 569T109 550Q109 549 114 549Q132 549 151 535T170 489Q170 464 154 447T109 429Z" style="stroke-width:3;"></path></g><g data-mml-node="TeXAtom" transform="translate(533,363) scale(0.707)" data-mjx-texclass="ORD"><g data-mml-node="mn"><path data-c="36" d="M42 313Q42 476 123 571T303 666Q372 666 402 630T432 550Q432 525 418 510T379 495Q356 495 341 509T326 548Q326 592 373 601Q351 623 311 626Q240 626 194 566Q147 500 147 364L148 360Q153 366 156 373Q197 433 263 433H267Q313 433 348 414Q372 400 396 374T435 317Q456 268 456 210V192Q456 169 451 149Q440 90 387 34T253 -22Q225 -22 199 -14T143 16T92 75T56 172T42 313ZM257 397Q227 397 205 380T171 335T154 278T148 216Q148 133 160 97T198 39Q222 21 251 21Q302 21 329 59Q342 77 347 104T352 209Q352 289 347 316T329 361Q302 397 257 397Z" style="stroke-width:3;"></path><path data-c="34" d="M462 0Q444 3 333 3Q217 3 199 0H190V46H221Q241 46 248 46T265 48T279 53T286 61Q287 63 287 115V165H28V211L179 442Q332 674 334 675Q336 677 355 677H373L379 671V211H471V165H379V114Q379 73 379 66T385 54Q393 47 442 46H471V0H462ZM293 211V545L74 212L183 211H293Z" transform="translate(500,0)" style="stroke-width:3;"></path></g></g></g></g></g>',1)])])),a[1]||(a[1]=s("mjx-assistive-mml",{unselectable:"on",display:"inline",style:{top:"0px",left:"0px",clip:"rect(1px, 1px, 1px, 1px)","-webkit-touch-callout":"none","-webkit-user-select":"none","-khtml-user-select":"none","-moz-user-select":"none","-ms-user-select":"none","user-select":"none",position:"absolute",padding:"1px 0px 0px 0px",border:"0px",display:"block",width:"auto",overflow:"hidden"}},[s("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[s("msup",null,[s("mn",null,"2"),s("mrow",{"data-mjx-texclass":"ORD"},[s("mn",null,"64")])])])],-1))]),a[3]||(a[3]=e(" 字节），如果使用一级页表存储所有映射关系，页表本身会占用无法接受的内存空间。Linux 使用四级页表（PGD → PUD → PMD → PTE）解决这个问题：页表采用类似字典树的结构，只有实际使用的页表项才会分配物理内存，未使用的区域不占用空间。",-1))]),a[5]||(a[5]=i(`<div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>2^32 / 4k * 4 = 4 MB</span></span>
<span class="line"><span>2^64 / 4k * 8 = 33554432 GB</span></span></code></pre></div><p><img src="`+h+'" alt=""></p><p>多级页表是一个类似于字典树的结构，多级多分支，对于一个 64 位的虚拟内存地址空间中的地址，会先对其进行前缀划分，从而确定其在多级页表上的查找路径。前 16 位不可用，中间的 32 位作为中间地址，后 16 位作为页内偏移；进程中保存着页表基地址，即 0 级页表的地址，在进行进程切换的时候，将该地址写入页表基地址寄存器即可完成进程的页表切换。</p><p>在需要读取某个地址上的数据的时候，先根据该地址的中间 36 位按顺序读取 4 级页表找到物理页的首地址，然后根据页内偏移找到该字节的地址，然后读取数据。</p><p>多级页表中，0 级页表必定存在，然后 1 级页表不一定都存在，因为 0 级页表中的地址不一定都是有效值，同理 2，3 级页表不一定存在，只有当需要的时候触发缺页异常，由系统临时分配，由此可以节省内存的空间；</p><h3 id="tlb-缓存" tabindex="-1">TLB 缓存 <a class="header-anchor" href="#tlb-缓存" aria-label="Permalink to “TLB 缓存”">​</a></h3><p>TLB（Translation Lookaside Buffer）是 CPU 内部的硬件缓存，用于缓存最近访问过的虚拟页到物理页的映射关系。TLB 命中时可直接获得物理地址，无需遍历多级页表。未命中时需重新查页表并更新 TLB。</p><h3 id="内存大页" tabindex="-1">内存大页 <a class="header-anchor" href="#内存大页" aria-label="Permalink to “内存大页”">​</a></h3><p>为了减少多级页表造成的访问延迟，可以使用内存大页来解决。linux 默认的页表大小是 4K，使用四级缓存，它允许调整页的大小为 2M 和 1G，相对应的页表采用 3 级页表和 2 级页表。这样可以减少访问路径的深度，同时一次加载一大块内存，可以显著减少访问的次数，但是这样会造成<strong>内部碎片</strong>的产生。同时，大页可以增加 TLB 的命中率和减少过期计算。</p><p><img src="'+o+`" alt=""></p><h2 id="用户态-malloc-流程" tabindex="-1">用户态 malloc 流程 <a class="header-anchor" href="#用户态-malloc-流程" aria-label="Permalink to “用户态 malloc 流程”">​</a></h2><p>在一个进程中，虚拟地址空间被划分成一个个 4K 大小的虚拟页，分别可以与真实的内存条上的物理内存页一一对应。</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> task_struct {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    pid_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pid;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    long</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> state;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mm_struct </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mm;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> files_struct </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">files;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> task_struct </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">parent;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> list_head children;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre></div><p>当进程调用 malloc 申请内存时，Linux 的内存分配流程如下：</p><ul><li><p>映射 用户程序发起内存分配请求。程序调用 malloc 函数申请内存，如果申请的内存小于 128KB，使用 brk 系统调用；如果申请的内存大于 128KB，使用 mmap 系统调用；但是不论大小如何，需要始终将内存按照分页进行管理。</p><p>虚拟内存分配，内核在进程的虚拟地址空间中分配一段连续的虚拟内存，此时只分配虚拟地址空间，不分配实际的物理内存；在页表 <code>struct mm_struct *mm</code> 中创建对应的页表项，但标记为<code>不存在</code>。</p></li><li><p>缺页异常 首次访问触发缺页异常，当程序首次访问这段内存时，由于页表项标记为<code>不存在</code>，CPU 触发缺页异常（Page Fault），操作系统接管处理缺页异常，核心函数 <code>do_page_fault</code> 负责处理；</p><p>物理内存分配，操作系统检查访问的虚拟地址是否合法，如果合法，分配物理内存页，更新页表，建立虚拟地址到物理地址的映射；将页表项标记为&quot;存在&quot;；</p><p>TLB 更新，新的页表项被添加到 TLB 中，后续访问可以直接通过 TLB 快速获取物理地址，如果 TLB 已满，根据硬件算法淘汰旧项；</p></li><li><p>访问 内存访问，程序可以正常访问内存，如果访问的地址超出分配范围，触发段错误（Segmentation Fault）；</p><p>内存释放，当调用 free 释放内存时，如果使用 brk 分配的内存，可能通过收缩堆来释放，如果使用 mmap 分配的内存，直接解除映射，对应的物理内存页被回收，页表项被标记为<code>不存在</code>，TLB 中的对应项被标记为无效；</p></li></ul><p>这个过程体现了 Linux 内存管理的几个重要特性：</p><ul><li>延迟分配：只有在实际使用时才分配物理内存</li><li>按需分页：通过缺页异常机制实现</li><li>写时复制：多个进程共享同一物理页，直到需要修改</li><li>内存回收：通过页面置换和内存压缩保持系统稳定</li></ul>`,17))])}const Q=n(d,[["render",c]]);export{E as __pageData,Q as default};
